import sys
def solve():
    lines = sys.stdin.read().split()
    if not lines: return
    n = int(lines[0])
    arr = list(map(int, lines[1:n+1]))
    ans = 0
    for i in range(n):
        curr = 0
        for j in range(i, n):
            curr ^= arr[j]
            if curr == 0:
                ans += 1
    print(ans)
if __name__ == '__main__':
    solve()
